class Solution:
    def lenOfVDiagonal(self, grid):
        n = len(grid)
        m = len(grid[0])
        DIRS = [(1, 1), (1, -1), (-1, -1), (-1, 1)]

        def clockwise(dr, dc):
            return (dc, -dr)

        def simulate(r, c, dr, dc, turn_at):
            length = 1
            expect = 2
            step = 0
            cur_r, cur_c, cur_dr, cur_dc = r, c, dr, dc
            turned = False
            while True:
                nr, nc = cur_r + cur_dr, cur_c + cur_dc
                if not (0 <= nr < n and 0 <= nc < m):
                    break
                if grid[nr][nc] != expect:
                    break
                length += 1
                cur_r, cur_c = nr, nc
                expect = 2 if expect == 0 else 0
                step += 1
                if (not turned) and turn_at == step:
                    cur_dr, cur_dc = clockwise(cur_dr, cur_dc)
                    turned = True
            return length

        ans = 0
        for r in range(n):
            for c in range(m):
                if grid[r][c] != 1:
                    continue
                ans = max(ans, 1)
                for dr, dc in DIRS:
                    max_steps = n + m
                    for turn_at in range(-1, max_steps + 1):
                        ans = max(ans, simulate(r, c, dr, dc, turn_at))
        return ans

