from functools import lru_cache
class Solution:
    def lenOfVDiagonal(self, grid):
        n = len(grid)
        m = len(grid[0])
        DIRS = [(1, 1), (1, -1), (-1, -1), (-1, 1)]

        def clockwise(dr, dc):
            return (dc, -dr)

        @lru_cache(maxsize=None)
        def extend(r, c, dr, dc, expect, can_turn):
            best = 0
            nr, nc = r + dr, c + dc
            if 0 <= nr < n and 0 <= nc < m and grid[nr][nc] == expect:
                nxt = 2 if expect == 0 else 0
                best = 1 + extend(nr, nc, dr, dc, nxt, can_turn)
            if can_turn:
                ndr, ndc = clockwise(dr, dc)
                nr2, nc2 = r + ndr, c + ndc
                if 0 <= nr2 < n and 0 <= nc2 < m and grid[nr2][nc2] == expect:
                    nxt = 2 if expect == 0 else 0
                    cand = 1 + extend(nr2, nc2, ndr, ndc, nxt, False)
                    if cand > best:
                        best = cand
            return best

        ans = 0
        for r in range(n):
            for c in range(m):
                if grid[r][c] == 1:
                    ans = max(ans, 1)
                    for dr, dc in DIRS:
                        ans = max(ans, 1 + extend(r, c, dr, dc, 2, True))
        extend.cache_clear()
        return ans

