var lenOfVDiagonal = function(grid) {
    const n = grid.length, m = grid[0].length;
    const DIRS = [[1, 1], [1, -1], [-1, -1], [-1, 1]];
    function clockwise(dr, dc) { return [dc, -dr]; }
    const memo = new Map();

    function extend(r, c, dr, dc, expect, canTurn) {
        const key = r + ',' + c + ',' + dr + ',' + dc + ',' + expect + ',' + (canTurn ? 1 : 0);
        if (memo.has(key)) return memo.get(key);
        let best = 0;
        const nr = r + dr, nc = c + dc;
        if (nr >= 0 && nr < n && nc >= 0 && nc < m && grid[nr][nc] === expect) {
            const nxt = expect === 0 ? 2 : 0;
            best = 1 + extend(nr, nc, dr, dc, nxt, canTurn);
        }
        if (canTurn) {
            const [ndr, ndc] = clockwise(dr, dc);
            const nr2 = r + ndr, nc2 = c + ndc;
            if (nr2 >= 0 && nr2 < n && nc2 >= 0 && nc2 < m && grid[nr2][nc2] === expect) {
                const nxt = expect === 0 ? 2 : 0;
                const cand = 1 + extend(nr2, nc2, ndr, ndc, nxt, false);
                if (cand > best) best = cand;
            }
        }
        memo.set(key, best);
        return best;
    }

    let ans = 0;
    for (let r = 0; r < n; r++) {
        for (let c = 0; c < m; c++) {
            if (grid[r][c] === 1) {
                ans = Math.max(ans, 1);
                for (const [dr, dc] of DIRS) {
                    ans = Math.max(ans, 1 + extend(r, c, dr, dc, 2, true));
                }
            }
        }
    }
    return ans;
};
